export default function Preloader() {
  const [mounted, setMounted] = useState(false);
  const [visible, setVisible] = useState(false);
  const [phase, setPhase] = useState<"loading" | "done">("loading");
  const reduceMotion = useReducedMotion();

  useEffect(() => {
    setMounted(true);
    if (typeof window === "undefined") return;
    const seen = window.sessionStorage.getItem(SESSION_KEY);
    if (!seen) {
      setVisible(true);
      document.documentElement.style.overflow = "hidden";
    }
  }, []);

  useEffect(() => {
    if (!visible) return;

    const linePhase = reduceMotion ? 200 : 1400;
    const hold = reduceMotion ? 200 : 500;

    const t1 = window.setTimeout(() => setPhase("done"), linePhase);
    const t2 = window.setTimeout(() => dismiss(), linePhase + hold);

    return () => {
      window.clearTimeout(t1);
      window.clearTimeout(t2);
    };
  }, [visible, reduceMotion]);

  function dismiss() {
    setVisible(false);
    window.sessionStorage.setItem(SESSION_KEY, "1");
    document.documentElement.style.overflow = "";
  }

  if (!mounted) return null;

  return (
    <AnimatePresence mode="wait">
      {visible ? (
        <motion.div
          key="preloader"
          className="fixed inset-0 z-[100] bg-[#0A0A0A] text-[#FAFAF7] pointer-events-auto overflow-hidden"
          initial={{ x: "0%" }}
          exit={{ x: "100%", pointerEvents: "none" }}
          transition={{ duration: 0.65, ease: CURTAIN_EASE }}
        >
          {/* Index superior izquierda */}
          <motion.div
            initial={{ opacity: 0, y: -6 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.7, delay: 0.1, ease: EASE }}
            className="absolute top-8 md:top-10 left-6 md:left-10 text-[10px] md:text-[11px] font-mono tracking-[0.3em] uppercase text-[#FAFAF7]/55"
          >
            01 / Index
          </motion.div>

          {/* Meta superior derecha */}
          <motion.div
            initial={{ opacity: 0, y: -6 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.7, delay: 0.15, ease: EASE }}
            className="absolute top-8 md:top-10 right-6 md:right-10 text-[10px] md:text-[11px] font-mono tracking-[0.3em] uppercase text-[#FAFAF7]/55"
          >
            2026 — Buenos Aires
          </motion.div>

          {/* Centro: logo + línea */}
          <div className="absolute inset-0 flex flex-col items-center justify-center gap-8">
            {/* Logo (fade + subtle scale) */}
            <motion.div
              initial={{ opacity: 0, scale: 0.94 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ duration: 1.2, delay: 0.25, ease: EASE }}
              className="w-[88px] md:w-[112px] text-[#FAFAF7]"
            >
              <InnhovexMark className="w-full h-auto" />
            </motion.div>

            {/* Línea horizontal de progreso */}
            <div className="relative w-[56vw] max-w-[520px] h-px bg-[#FAFAF7]/12">
              <motion.div
                initial={{ scaleX: 0 }}
                animate={{ scaleX: 1 }}
                transition={{
                  duration: reduceMotion ? 0.2 : 1.1,
                  delay: 0.25,
                  ease: EASE,
                }}
                className="absolute inset-0 bg-[#FAFAF7] origin-left"
              />
            </div>
          </div>

          {/* Wordmark inferior izquierda */}
          <motion.div
            initial={{ opacity: 0, y: 6 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.7, delay: 0.2, ease: EASE }}
            className="absolute bottom-8 md:bottom-10 left-6 md:left-10 text-[10px] md:text-[11px] font-mono tracking-[0.3em] uppercase text-[#FAFAF7]/55"
          >
            Innhovex — Estudio digital
          </motion.div>

          {/* Estado inferior derecha */}
          <motion.div
            initial={{ opacity: 0, y: 6 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.7, delay: 0.2, ease: EASE }}
            className="absolute bottom-8 md:bottom-10 right-6 md:right-10 text-[10px] md:text-[11px] font-mono tracking-[0.3em] uppercase text-[#FAFAF7]/55"
          >
            {phase === "loading" ? "Loading" : "Ready"}
          </motion.div>
        </motion.div>
      ) : null}
    </AnimatePresence>
  );
}
